// ── MAP DOMAIN ──────────────────────────────────────────────────────────────
const domainMap = [
  { data: strengthEx, domain: 'strength' },
  { data: staminaEx,  domain: 'stamina' },
  { data: coordEx,    domain: 'coordination' },
  { data: flexEx,     domain: 'flexibility' },
];

// ── SEGMENT NORMALISER ───────────────────────────────────────────────────────
function normaliseSegment(s) {
  const map = {
    'lower':     'lower',
    'upper':     'upper',
    'full body': 'full_body',
    'full_body': 'full_body',
    'core':      'core',
  };
  return map[s.toLowerCase()] || 'full_body';
}

// ── SENSIBLE DEFAULTS BY DOMAIN ──────────────────────────────────────────────
function getDefaults(domain) {
  if (domain === 'coordination') return { sets: 3, reps_min: 1, reps_max: 1, rest: 30 };
  if (domain === 'flexibility')  return { sets: 1, reps_min: 1, reps_max: 1, rest: 0 };
  return { sets: 3, reps_min: 8, reps_max: 12, rest: 90 };
}

// ── BUILD ROWS ───────────────────────────────────────────────────────────────
const allRows = [];
for (const { data, domain } of domainMap) {
  const def = getDefaults(domain);
  for (const ex of data) {
    allRows.push({
      name:              ex.n,
      domain,
      movement_pattern:  ex.p,
      tier:              ex.t,
      segment:           normaliseSegment(ex.s),
      equipment:         ex.e,
      bilateral:         ex.b,
      load_bearing:      ex.lb,
      contraindications: ex.c || '',
      technique_start:   ex.start,
      technique_move:    ex.move,
      technique_avoid:   ex.avoid,
      gif_search_name:   ex.n,
      default_sets:      def.sets,
      default_reps_min:  def.reps_min,
      default_reps_max:  def.reps_max,
      default_rest_secs: def.rest,
    });
  }
}

// ── SEED ─────────────────────────────────────────────────────────────────────
async function seed() {
  console.log(`Seeding ${allRows.length} exercises...`);

  // Clear existing
  const { error: delErr } = await supabase.from('alongside_exercises').delete().neq('id', '00000000-0000-0000-0000-000000000000');
  if (delErr) { console.error('Delete failed:', delErr.message); process.exit(1); }
  console.log('Cleared existing rows.');

  // Insert in batches of 50
  const BATCH = 50;
  let inserted = 0;
  for (let i = 0; i < allRows.length; i += BATCH) {
    const batch = allRows.slice(i, i + BATCH);
    const { data, error } = await supabase.from('alongside_exercises').insert(batch).select('id');
    if (error) {
      console.error(`Batch ${Math.floor(i/BATCH)+1} failed:`, error.message);
      process.exit(1);
    }
    inserted += data.length;
    console.log(`Batch ${Math.floor(i/BATCH)+1}: inserted ${data.length} rows (total: ${inserted})`);
  }

  console.log(`
Seeding complete. ${inserted} exercises inserted.`);
  if (inserted !== allRows.length) {
    console.warn(`WARNING: Expected ${allRows.length}, got ${inserted}`);
    process.exit(1);
  }
  process.exit(0);
}

seed().catch(err => { console.error('Unexpected error:', err); process.exit(1); })

seed().catch(err => { console.error(err); process.exit(1); });
